func extractMiningProfitabilityV16(ctx *extract.Ctx, res *extract.Res, head *common.ActorHead, st *reward16.State) error {
	blkraw, err := ctx.D.ChainBlockstore().Get(ctx.C, head.Global.Power.Head)
	if err != nil {
		return fmt.Errorf("load head block data for power state (%s): %w", head.Head, err)
	}

	state, err := vm.DumpActorState(consensus.NewTipSetExecutor(filcns.RewardFunc).NewActorRegistry(), head.Global.Power, blkraw.RawData())
	if err != nil {
		return fmt.Errorf("dump actor state for %s (%s): %w", head.Addr, head.Head, err)
	}

	pwrState, ok := state.(*power16.State)
	if !ok {
		return fmt.Errorf("expecting *power16.State, got %T", pwrState)
	}

	qaPower := miner16.QAPowerForWeight(sectorSize32GiB, 180, big.Zero())

	storagePledge := miner16.ExpectedRewardForPower(st.ThisEpochRewardSmoothed, pwrState.ThisEpochQAPowerSmoothed, miner16.QAPowerMax(sectorSize32GiB), miner16.PreCommitDepositProjectionPeriod)

	var epochsSinceRampStart int64
	var rampDurationEpochs uint64
	if pwrState.RampStartEpoch > 0 {
		epochsSinceRampStart = int64(head.Epoch) - pwrState.RampStartEpoch
		rampDurationEpochs = pwrState.RampDurationEpochs
	}
	initPledge := miner16.InitialPledgeForPower(qaPower, st.ThisEpochBaselinePower, st.ThisEpochRewardSmoothed, pwrState.ThisEpochQAPowerSmoothed, head.CirculatingSupply.FilCirculating, epochsSinceRampStart, rampDurationEpochs)

	// we just ignore the influence of spaceRacePledgeCap here
	consensusPledge := big.Sub(initPledge, storagePledge)

	detail := model.MiningProfitabilityDetail{
		ExpectedDayReward:         miner16.ExpectedRewardForPower(st.ThisEpochRewardSmoothed, pwrState.ThisEpochQAPowerSmoothed, qaPower, builtin16.EpochsInDay),
		InitialPledge:             initPledge,
		InitialConsensusPledge:    consensusPledge,
		InitialStoragePledge:      storagePledge,
		ProjectionOfInitialPledge: storagePledge, // TODO: projection is just equal to the init storage power here, correct me if I'm wrong
		ProjectionOfFaultFee:      miner16.ExpectedRewardForPower(st.ThisEpochRewardSmoothed, pwrState.ThisEpochQAPowerSmoothed, qaPower, abi.ChainEpoch(builtin16.EpochsInDay*351)/100),
		Mined:                     st.TotalStoragePowerReward,
	}

	id, err := GenRegularHeadID(head.Head, head.Addr, head.Epoch)
	if err != nil {
		return fmt.Errorf("gen regular id: %w", err)
	}

	res.Docs = append(res.Docs, &model.MiningProfitability{
		ActorStateExBasic: model.ActorStateExBasic{
			ID:    id,
			Path:  []cid.Cid{head.Head, head.Global.Power.Head},
			Addr:  head.Addr,
			Epoch: head.Epoch,
		},

		Detail: detail,
	})

	return nil
}
